-- Update Robotics and AI course content: fix grammar, improve readability
-- Course: robotics-and-ai (25 lessons, 5 modules x 5)

-- Module 1, Lesson 0: Kaj je robot?
UPDATE course_lessons
SET content = E'# Kaj je robot?\n\nRobot je naprava, ki lahko **zazna** okolje, **razmišlja** o tem, kaj zazna, in **ukrepa** na podlagi svojih odločitev.\n\n---\n\n## Trije deli vsakega robota\n\n### 1. Senzorji (čutila)\n\nSenzorji so kot robotova čutila. Kamere so njegove oči, mikrofoni so ušesa, senzorji pritiska pa njegov dotik.\n\n### 2. Procesor (možgani)\n\nProcesor je robotov mozeg. Tu se izvaja program, ki sprejema odločitve na podlagi informacij iz senzorjev.\n\n### 3. Aktuatorji (mišice)\n\nAktuatorji so robotove mišice -- motorji, ki premikajo roke, kolesa ali druge dele.\n\n---\n\n## Primeri robotov\n\n- **Industrijski roboti** -- sestavljajo avtomobile v tovarnah.\n- **Kirurški roboti** -- pomagajo zdravnikom pri operacijah.\n- **Raziskovalni roboti** -- kot rover na Marsu.\n- **Domači roboti** -- sesalniki kot Roomba.\n\n---\n\n## Razmisli\n\nAli je pametni telefon robot? Ima senzorje (kamero, mikrofon) in procesor, toda nima aktuatorjev za gibanje. Zato ni pravi robot, je pa **pameten** aparat!\n\n---\n\n## Naloga\n\nNariši svojega sanjskega robota. Označi njegove senzorje, procesor in aktuatorje. Kakšno nalogo bi opravljal?',
    updated_at = NOW()
WHERE title = 'Kaj je robot?'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 1, Lesson 1: Zgodovina robotike
UPDATE course_lessons
SET content = E'# Zgodovina robotike\n\nBeseda "robot" izvira iz češke besede **"robota"**, ki pomeni prisilno delo. Prvič jo je uporabil pisatelj Karel Čapek leta 1920.\n\n---\n\n## Mejniki v zgodovini\n\n### Antika in srednji vek\n\n- Stari Grki so gradili **avtomatone** -- mehanske figure, ki so se premikale.\n- Leonardo da Vinci je zasnoval mehanskega viteza leta 1495.\n\n### 20. stoletje\n\n- **1954** -- George Devol izumi prvega industrijskega robota Unimate.\n- **1966** -- Shakey, prvi mobilni robot z AI, razume enostavne ukaze.\n- **1997** -- Robot Sojourner pristane na Marsu.\n\n### 21. stoletje\n\n- **2000** -- Honda predstavi ASIMO, humanoidnega robota.\n- **2011** -- IBM Watson zmaga v televizijskem kvizu Jeopardy.\n- **2020+** -- AI roboti se učijo hoditi, govoriti in pomagati ljudem.\n\n---\n\n## Slovenci in robotika\n\nAli si vedel, da ima Slovenija odlične inženirje robotike? Na Univerzi v Ljubljani in Mariboru razvijajo napredne robote za industrijo in medicino.\n\n---\n\n## Aktivnost\n\nUstvari časovnico robotike z najmanj 5 mejniki. Kateri izum se ti zdi najpomembnejši in zakaj?',
    updated_at = NOW()
WHERE title = 'Zgodovina robotike'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 1, Lesson 2: Vrste robotov
UPDATE course_lessons
SET content = E'# Vrste robotov\n\nRoboti prihajajo v vseh oblikah in velikostih. Spoznajmo glavne kategorije.\n\n---\n\n## 1. Industrijski roboti\n\nTo so veliki robotski kraki v tovarnah. Opravljajo ponavljajoče naloge: varjenje, barvanje, sestavljanje.\n\n- **Prednost:** hitri, natančni, ne potrebujejo počitka.\n- **Primer:** ABB, KUKA roboti.\n\n---\n\n## 2. Mobilni roboti\n\nRoboti, ki se premikajo po prostoru.\n\n- **Na kolesih:** dostavni roboti, Roomba.\n- **Na nogah:** Boston Dynamics Spot (pes), Atlas (humanoid).\n- **Leteči:** droni za dostavo in fotografijo.\n\n---\n\n## 3. Humanoidni roboti\n\nRoboti v obliki človeka. Imajo glavo, trup, roke in noge.\n\n- **Primer:** Tesla Optimus, Sophia.\n- **Izziv:** človekova hoja je izjemno težka za kopiranje!\n\n---\n\n## 4. Sodelovalni roboti (coboti)\n\nManjši roboti, ki varno delajo skupaj z ljudmi.\n\n- Uporabljajo se v majhnih delavnicah.\n- Imajo senzorje, da se ustavijo, če zaznajo človeka.\n\n---\n\n## 5. Mikro in nano roboti\n\nDrobceni roboti za medicino -- nekoč bodo potovali po našem telesu in popravljali celice!\n\n---\n\n## Naloga\n\nIzberi eno vrsto robota in napiši kratek esej (5--10 stavkov) o tem, kako bi ta robot lahko pomagal v tvoji šoli.',
    updated_at = NOW()
WHERE title = 'Vrste robotov'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 1, Lesson 3: Robotika v Sloveniji
UPDATE course_lessons
SET content = E'# Robotika v Sloveniji\n\nSlovenija je majhna država z velikimi dosežki v robotiki!\n\n---\n\n## Univerza v Ljubljani\n\nFakulteta za elektrotehniko ima enega najmodernejših laboratorijev za robotiko v regiji. Razvijajo:\n\n- **Humanoidne robote** za pomoč starejšim.\n- **Industrijske robote** za slovenska podjetja.\n- **Medicinske robote** za rehabilitacijo.\n\n---\n\n## Slovenska podjetja\n\n### RoboticsX\n\nRazvija napredne algoritme za robotsko manipulacijo.\n\n### Yaskawa Slovenija\n\nV Kočevju proizvajajo industrijske robote za ves svet.\n\n---\n\n## RoboLiga\n\nAli si vedel, da imamo v Sloveniji tekmovanja v robotiki za mlade? **RoboLiga** organizira tekmovanja, kjer ekipe učencev gradijo in programirajo robote za različne naloge.\n\n---\n\n## Zakaj je robotika pomembna za Slovenijo?\n\n- Slovenija ima močno industrijo, ki potrebuje avtomatizacijo.\n- Mladi inženirji robotike imajo odlične zaposlitvene možnosti.\n- Robotika združuje znanje matematike, fizike, informatike in inženirstva.\n\n---\n\n## Projekt\n\nRazišči, ali v tvoji okolici obstaja robotski krožek ali tekmovanje. Napiši načrt, kako bi se pridružil ali ustanovil svojega.',
    updated_at = NOW()
WHERE title = 'Robotika v Sloveniji'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 1, Lesson 4: Moj prvi virtualni robot
UPDATE course_lessons
SET content = E'# Moj prvi virtualni robot\n\nPreden gradimo fizičnega robota, se naučimo osnov z virtualnim!\n\n---\n\n## Simulatorji robotov\n\nSimulator je program, ki posnema resničnega robota v virtualnem svetu. To je kot videoigra, le da se učiš resničnih konceptov.\n\n### Prednosti simulatorjev:\n\n- **Brezplačni** -- ne potrebuješ dragih delov.\n- **Varni** -- ne moreš ničesar zlomiti.\n- **Hitri** -- poskuse ponoviš v sekundah.\n\n---\n\n## Osnovni ukazi za robota\n\nVsak robot razume osnovne ukaze:\n\n```\nPREMIKNI_NAPREJ(koraki)\nZAVRTI_LEVO(stopinje)\nZAVRTI_DESNO(stopinje)\nPOBERI(predmet)\nODLOŽI(predmet)\nČAKAJ(sekunde)\n```\n\n---\n\n## Primer programa\n\nNaš robot mora pobrati žogo in jo odnesti na cilj:\n\n```\nPREMIKNI_NAPREJ(3)\nZAVRTI_LEVO(90)\nPREMIKNI_NAPREJ(2)\nPOBERI(žoga)\nZAVRTI_DESNO(180)\nPREMIKNI_NAPREJ(5)\nODLOŽI(žoga)\n```\n\n---\n\n## Tvoja naloga\n\nNapiši program za naslednji scenarij:\n\n1. Robot stoji na začetku labirinta.\n2. Mora najti pot do izhoda.\n3. Na poti mora pobrati 2 zvezdici.\n\nNariši labirint in zapiši ukaze!',
    updated_at = NOW()
WHERE title = 'Moj prvi virtualni robot'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 2, Lesson 0: Kako robot vidi svet
UPDATE course_lessons
SET content = E'# Kako robot vidi svet\n\nMi vidimo svet skozi oči. Robot "vidi" skozi **senzorje** -- naprave, ki merijo različne lastnosti okolja.\n\n---\n\n## Vrste senzorjev\n\n### Kamere (vid)\n\nKamere zajamejo slike, ki jih robot analizira z AI.\n\n- **RGB kamere** -- vidijo barve kot mi.\n- **Globinske kamere** -- merijo razdaljo do objektov.\n- **Infrardeče kamere** -- vidijo v temi.\n\n### Ultrazvočni senzorji (sluh)\n\nDelujejo kot netopirji -- pošljejo zvočni val in merijo, kdaj se vrne.\n\n- Uporabljajo se za merjenje razdalje.\n- Roomba jih uporablja za zaznavanje sten.\n\n### Senzorji dotika\n\nRobot čuti pritisk, temperaturo in teksturo.\n\n- **Pritiskovni senzorji** -- ali je robot trčil v steno?\n- **Temperaturni senzorji** -- ali je predmet vroč?\n- **Silomer** -- kako močno robot drži predmet?\n\n### Žiroskop in pospeškometer\n\nMerita nagib in pospešek robota -- tako kot v tvojem telefonu!\n\n---\n\n## Eksperiment\n\nVzemi telefon in odpri aplikacijo, ki prikazuje senzorske podatke (npr. Phyphox). Koliko senzorjev ima tvoj telefon? Katere bi lahko nadomestili senzorje robota?',
    updated_at = NOW()
WHERE title = 'Kako robot vidi svet'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 2, Lesson 1: Računalniški vid
UPDATE course_lessons
SET content = E'# Računalniški vid\n\nRačunalniški vid je veja AI, ki uči računalnike **razumeti slike**.\n\n---\n\n## Kako robot "vidi" sliko?\n\nZa nas je slika mačke očitna. Za robota je slika le mreža številk -- vsak piksel ima vrednost za rdečo, zeleno in modro barvo.\n\n```\nSlika 3x3:\n[255,0,0]  [255,0,0]  [0,255,0]\n[255,0,0]  [0,0,0]    [0,255,0]\n[0,0,255]  [0,0,255]  [0,0,255]\n```\n\n---\n\n## Koraki računalniškega vida\n\n### 1. Zajem slike\n\nKamera zajame sliko in jo pretvori v številke.\n\n### 2. Obdelava\n\n- **Filtriranje** -- odstranjevanje šuma.\n- **Robovi** -- iskanje mej med objekti.\n- **Barve** -- ločevanje po barvah.\n\n### 3. Prepoznavanje\n\nAI model analizira obdelano sliko in prepozna objekte.\n\n- "To je mačka z 95-odstotno verjetnostjo."\n- "Na sliki sta 2 osebi in 1 pes."\n\n---\n\n## Uporaba v robotiki\n\n- **Samovozeči avtomobili** -- prepoznavanje prometnih znakov.\n- **Industrijski roboti** -- kontrola kakovosti.\n- **Droni** -- sledenje objektom.\n\n---\n\n## Aktivnost\n\nVzemi 5 slik različnih predmetov. Kakšne značilnosti bi robot moral prepoznati, da bi jih ločil? Naredi tabelo značilnosti za vsak predmet.',
    updated_at = NOW()
WHERE title = 'Računalniški vid'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 2, Lesson 2: Senzorji za navigacijo
UPDATE course_lessons
SET content = E'# Senzorji za navigacijo\n\nKako robot ve, kje je in kam mora iti?\n\n---\n\n## GPS -- Globalni pozicijski sistem\n\n- Deluje s pomočjo satelitov v orbiti.\n- Natančnost: 2--5 metrov na prostem.\n- **Problem:** ne deluje v zaprtih prostorih!\n\n---\n\n## LIDAR -- Lasersko merjenje razdalje\n\nLIDAR je kot 3D-skener okolja:\n\n1. Pošlje laserski žarek.\n2. Meri čas, da se žarek vrne.\n3. Ustvari 3D-zemljevid okolja.\n\nSamovozeči avtomobili uporabljajo LIDAR za "videnje" ceste.\n\n---\n\n## SLAM -- Simultano lociranje in kartiranje\n\nSLAM je tehnika, s katero robot **hkrati** ugotavlja, kje je, in gradi zemljevid okolja.\n\nPredstavljaj si, da te nekdo pusti v temen labirint:\n\n1. Tipaš stene okrog sebe.\n2. Zapomniš si, kje si že bil.\n3. Postopoma gradiš zemljevid v glavi.\n\nTo je SLAM za robote!\n\n---\n\n## Senzor odometrije\n\nMeri, koliko so se kolesa zavrtela. Iz tega izračuna, kako daleč je robot šel.\n\n- **Problem:** napake se kopičijo! Kolesa drsijo.\n\n---\n\n## Naloga\n\nNačrtuj navigacijski sistem za robota, ki dostavlja pakete v tvojem mestu. Katere senzorje bi uporabil? Nariši shemo.',
    updated_at = NOW()
WHERE title = 'Senzorji za navigacijo'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 2, Lesson 3: Zbiranje in analiza podatkov
UPDATE course_lessons
SET content = E'# Zbiranje in analiza podatkov\n\nSenzorji zbirajo ogromne količine podatkov. Kako jih robot razume?\n\n---\n\n## Vrste podatkov\n\n### Številčni podatki\n\n- Temperatura: 23,5 °C\n- Razdalja: 1,82 m\n- Hitrost: 0,5 m/s\n\n### Slikovni podatki\n\n- Slike iz kamere (milijone pikslov).\n- Video posnetki (30 slik na sekundo!).\n\n### Zvočni podatki\n\n- Glasovni ukazi.\n- Zvoki okolja.\n\n---\n\n## Filtriranje šuma\n\nSenzorji niso popolni -- včasih dajo napačne podatke (šum).\n\n**Primer:** temperaturni senzor v eni sekundi:\n\n```\n23.5, 23.6, 99.1, 23.4, 23.5\n```\n\nVrednost 99,1 je očitno napaka! Robot mora znati filtrirati šum.\n\n### Tehnike filtriranja:\n\n- **Povprečenje** -- vzameš povprečje zadnjih N meritev.\n- **Mediana** -- vzameš srednjo vrednost (ignorira ekstreme).\n- **Kalmanov filter** -- napredna tehnika, ki upošteva fizikalne zakone.\n\n---\n\n## Fuzija senzorjev\n\nKombiniranje podatkov iz več senzorjev za boljšo sliko:\n\n- GPS + odometrija = boljša lokacija.\n- Kamera + LIDAR = boljše zaznavanje objektov.\n\n---\n\n## Naloga\n\nPridobi 10 meritev temperature v svoji sobi (vsako minuto). Izračunaj povprečje in mediano. Ali se razlikujeta? Zakaj?',
    updated_at = NOW()
WHERE title = 'Zbiranje in analiza podatkov'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 2, Lesson 4: Projekt: Senzorska mreža
UPDATE course_lessons
SET content = E'# Projekt: Senzorska mreža\n\nV tem projektu boš načrtoval senzorsko mrežo za pameten dom.\n\n---\n\n## Scenarij\n\nTvoja družina želi pameten dom. Načrtuj sistem, ki:\n\n- Meri temperaturo in vlažnost v vsaki sobi.\n- Zaznava gibanje (varnost).\n- Nadzoruje porabo električne energije.\n- Opozori, če nekdo pozabi zapreti okno, ko pada dež.\n\n---\n\n## Korak 1: Načrt senzorjev\n\nZa vsako sobo določi:\n\n| Soba | Senzorji | Zakaj |\n|------|----------|-------|\n| Dnevna soba | Temp., gibanje, svetloba | Udobje, varnost |\n| Kuhinja | Temp., dim, plin | Varnost |\n| Spalnica | Temp., svetloba, zvok | Udobje, spanje |\n\n---\n\n## Korak 2: Povezovanje\n\nKako bodo senzorji komunicirali?\n\n- **WiFi** -- za senzorje blizu usmerjevalnika.\n- **Bluetooth** -- za bližnje naprave.\n- **Zigbee** -- za senzorje z majhno porabo.\n\n---\n\n## Korak 3: Pravila\n\nNapiši pravila za svoj pametni dom:\n\n```\nČE temperatura > 25 °C IN okno = zaprto\n  POTEM pošlji obvestilo "Odpri okno!"\n\nČE gibanje = zaznano IN čas > 23:00 IN nihče_doma = true\n  POTEM vklopi alarm\n```\n\n---\n\n## Korak 4: Vizualizacija\n\nNariši tloris doma in označi, kje bi postavil katere senzorje. Dodaj legendo z barvami za vsako vrsto senzorja.\n\n---\n\n## Bonus\n\nKateri podatki bi lahko izboljšali delovanje tvojega sistema, če bi dodal AI? Na primer: AI se nauči, kdaj se družina vrne domov, in vnaprej uravna temperaturo.',
    updated_at = NOW()
WHERE title = 'Projekt: Senzorska mreža'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 3, Lesson 0: Strojno učenje za robote
UPDATE course_lessons
SET content = E'# Strojno učenje za robote\n\nNamesto da robotu povemo vsako pravilo, ga lahko **naučimo** iz izkušenj.\n\n---\n\n## Tradicionalno programiranje proti strojnemu učenju\n\n**Tradicionalno:**\n\n```\nČE ovira_pred_teboj POTEM zavij_levo\nČE pot_prosta POTEM pojdi_naprej\n```\n\nProblem: ne moreš predvideti vsake situacije!\n\n**Strojno učenje:**\n\n```\nPokaži robotu 10.000 primerov:\n- Slika ceste → pravilna akcija\nRobot se sam nauči pravil!\n```\n\n---\n\n## Vrste strojnega učenja\n\n### Nadzorovano učenje\n\nRobotu pokažeš primere s pravilnimi odgovori.\n\n- "Ta slika = mačka, ta slika = pes."\n- Robot se nauči razlikovati.\n\n### Nenadzorovano učenje\n\nRobot sam najde vzorce v podatkih.\n\n- "Razvrsti te predmete v skupine."\n- Robot ugotovi, da so nekateri predmeti podobni.\n\n### Spodbujevano učenje (Reinforcement Learning)\n\nRobot se uči s poskušanjem:\n\n1. Poskusi akcijo.\n2. Dobi nagrado (dobro) ali kazen (slabo).\n3. Sčasoma se nauči najboljše strategije.\n\nTo je kot učenje vožnje s kolesom -- padeš, vstaneš, poskusiš znova!\n\n---\n\n## Primer\n\nRobot se uči hoditi:\n\n- Nagrada: korak naprej = +1 točka.\n- Kazen: padec = -10 točk.\n- Po 1000 poskusih se nauči hoditi!\n\n---\n\n## Razmisli\n\nKatero vrsto učenja bi uporabil za robota, ki:\n\n1. Sortira smeti? (nadzorovano)\n2. Igra šah? (spodbujevano)\n3. Organizira skladišče? (nenadzorovano)',
    updated_at = NOW()
WHERE title = 'Strojno učenje za robote'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 3, Lesson 1: Nevronske mreže
UPDATE course_lessons
SET content = E'# Nevronske mreže\n\nNevronske mreže so navdihnjene z delovanjem človeških **možganov**.\n\n---\n\n## Kako delujejo možgani?\n\nMožgani imajo ~86 milijard nevronov (živčnih celic).\n\n- Vsak nevron sprejme signale od drugih nevronov.\n- Če je signal dovolj močan, pošlje svoj signal naprej.\n- Povezave med nevroni se krepijo z vajo.\n\n---\n\n## Umetne nevronske mreže\n\nUmetna nevronska mreža posnema ta princip:\n\n```\nVhod → [Nevron 1] → [Nevron 2] → [Nevron 3] → Izhod\n         ↕              ↕              ↕\n       [Nevron 4] → [Nevron 5] → [Nevron 6]\n```\n\n### Plasti:\n\n1. **Vhodna plast** -- sprejme podatke (sliko, besedilo ...).\n2. **Skrite plasti** -- procesirajo podatke, iščejo vzorce.\n3. **Izhodna plast** -- dá končni odgovor.\n\n---\n\n## Učenje nevronske mreže\n\n1. Mreža dobi vhodni podatek.\n2. Izračuna odgovor.\n3. Primerja s pravilnim odgovorom.\n4. Popravi povezave (uteži) -- to je "učenje"!\n5. Ponovi 1000-krat.\n\n---\n\n## Globoko učenje (Deep Learning)\n\nKo ima mreža veliko skritih plasti, govorimo o **globokem učenju**. To je tehnologija za:\n\n- Prepoznavanje obrazov.\n- Samovozeče avtomobile.\n- ChatGPT in podobne modele.\n\n---\n\n## Aktivnost\n\nS tremi prijatelji simulirajte nevronsko mrežo: eden je vhod, dva sta skrita plast, eden je izhod. Pošiljajte si številke in opazujte, kako se "odgovor" spreminja.',
    updated_at = NOW()
WHERE title = 'Nevronske mreže'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 3, Lesson 2: Načrtovanje poti
UPDATE course_lessons
SET content = E'# Načrtovanje poti\n\nKako robot najde najboljšo pot od točke A do točke B?\n\n---\n\n## Problem\n\nRobot mora:\n\n- Priti od starta do cilja.\n- Se izogniti oviram.\n- Najti **najkrajšo** ali **najhitrejšo** pot.\n\n---\n\n## Algoritem A* (A-zvezdica)\n\nNajbolj priljubljen algoritem za načrtovanje poti.\n\n### Kako deluje:\n\n1. Začni na startnem polju.\n2. Poglej vsa sosednja polja.\n3. Za vsako polje izračunaj:\n   - g = razdalja od starta\n   - h = ocenjena razdalja do cilja\n   - f = g + h\n4. Premakni se na polje z najnižjim f.\n5. Ponavljaj, dokler ne prideš do cilja.\n\n### Primer na mreži:\n\n```\nS . . . .\n. X X . .\n. . X . .\n. . . . C\n\nS = start, C = cilj, X = ovira\n```\n\nRobot ne gre skozi X-polja, ampak jih obide.\n\n---\n\n## Dijkstrov algoritem\n\nPodobno kot A*, ampak brez ocene h.\n\n- Bolj počasen, toda vedno najde optimalno pot.\n\n---\n\n## Roboti v resničnem svetu\n\n- **Amazon skladišča:** tisoči robotov se premikajo med policami.\n- **Samovozeči avti:** načrtujejo pot skozi promet v realnem času.\n\n---\n\n## Naloga\n\nNa mrežastem papirju (10x10) nariši labirint. Nato ročno izvedi algoritem A*, da najdeš pot. Zapiši korake!',
    updated_at = NOW()
WHERE title = 'Načrtovanje poti'
