-- Module 3, Lesson 3: Odločanje robota
UPDATE course_lessons
SET content = E'# Odločanje robota\n\nKako se robot odloči, kaj narediti?\n\n---\n\n## Odločitvena drevesa\n\nNajenostavnejši način za odločanje:\n\n```\nAli je pred mano ovira?\n├── DA → Ali je levo prosto?\n│   ├── DA → Zavij levo\n│   └── NE → Zavij desno\n└── NE → Pojdi naprej\n```\n\n---\n\n## Končni avtomati (State Machines)\n\nRobot je vedno v enem od **stanj** in prehaja med njimi:\n\n```\n[RAZISKUJ] --najdi predmet--> [POBERI]\n[POBERI] --uspeh--> [ODNESI]\n[POBERI] --neuspeh--> [RAZISKUJ]\n[ODNESI] --cilj dosežen--> [RAZISKUJ]\n```\n\nTo je kot igra, kjer ima lik različne "načine" (hoja, tek, boj).\n\n---\n\n## Verjetnostno odločanje\n\nVčasih robot ni 100 % prepričan:\n\n- "80 % verjetnost, da je to mačka."\n- "20 % verjetnost, da je to pes."\n\nRobot izračuna **pričakovano vrednost** vsake akcije:\n\n- Akcija A: 80 % x 10 točk = 8 točk.\n- Akcija B: 50 % x 20 točk = 10 točk.\n- Izbere B, ker ima višjo pričakovano vrednost!\n\n---\n\n## Večagentno odločanje\n\nKo več robotov dela skupaj, se morajo usklajevati:\n\n- Kdo gre kam?\n- Kako se izognejo trkom?\n- Kako si razdelijo naloge?\n\n---\n\n## Naloga\n\nNariši odločitveno drevo za robota, ki dostavlja pice. Upoštevaj: vreme, promet, pravilnost naslova, stanje pice.',
    updated_at = NOW()
WHERE title = 'Odločanje robota'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 3, Lesson 4: Projekt: AI agent v igri
UPDATE course_lessons
SET content = E'# Projekt: AI agent v igri\n\nZgradimo AI agenta, ki igra enostavno igro!\n\n---\n\n## Igra: Robot zbira diamante\n\nPravila:\n\n- Robot je na mreži 5x5.\n- Na mreži so 3 diamanti in 2 pasti.\n- Robot mora pobrati vse diamante in se izogniti pastim.\n- Za vsak diamant dobi +10 točk, za past -20 točk.\n\n---\n\n## Načrtovanje AI agenta\n\n### Strategija 1: Naključno\n\n```\nVsak korak: izberi naključno smer.\nEnostavnost: preprosto.\nUčinkovitost: slaba.\n```\n\n### Strategija 2: Požrešna (Greedy)\n\n```\nVsak korak: pojdi proti najbližjemu diamantu.\nIzogni se pastim, ki so na poti.\nEnostavnost: srednja.\nUčinkovitost: dobra.\n```\n\n### Strategija 3: Načrtovana\n\n```\n1. Najdi vse diamante.\n2. Izračunaj najkrajšo pot, ki obišče vse.\n3. Izogni se vsem pastim.\nEnostavnost: težka.\nUčinkovitost: odlična.\n```\n\n---\n\n## Tvoja naloga\n\n1. Na papirju nariši mrežo 5x5.\n2. Postavi 3 diamante (D) in 2 pasti (P).\n3. Postavi robota na začetno polje.\n4. Izvedi vse 3 strategije ročno.\n5. Za vsako strategijo zapiši:\n   - Koliko korakov je potreboval robot?\n   - Koliko točk je dosegel?\n   - Ali je padel v past?\n\n---\n\n## Bonus\n\nDodaj novo pravilo: robot ima le 15 korakov. Katera strategija zdaj zmaga? Zakaj?',
    updated_at = NOW()
WHERE title = 'Projekt: AI agent v igri'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 4, Lesson 0: Kaj pomeni avtonomnost?
UPDATE course_lessons
SET content = E'# Kaj pomeni avtonomnost?\n\n**Avtonomni robot** je robot, ki deluje sam, brez človeškega nadzora.\n\n---\n\n## Stopnje avtonomnosti\n\n### Stopnja 1: Daljinsko vodenje\n\nČlovek nadzoruje vsako gibanje robota.\n\n- Primer: dron s kontrolerjem.\n- Robot sam ne sprejema odločitev.\n\n### Stopnja 2: Polavtonomnost\n\nRobot izvaja naloge sam, človek nadzoruje.\n\n- Primer: tempomat v avtu.\n- Robot sledi pravilom, človek prevzame v nujnih primerih.\n\n### Stopnja 3: Pogojna avtonomnost\n\nRobot sam vozi v določenih razmerah.\n\n- Primer: Tesla Autopilot na avtocesti.\n- Človek mora biti pripravljen prevzeti.\n\n### Stopnja 4: Visoka avtonomnost\n\nRobot sam obvladuje skoraj vse situacije.\n\n- Primer: Waymo taxi v določenih mestih.\n- Človek ni potreben, toda robot deluje le v znanih okoljih.\n\n### Stopnja 5: Polna avtonomnost\n\nRobot sam deluje v vseh situacijah.\n\n- To za avtomobile še ne obstaja!\n- Morda v prihodnosti?\n\n---\n\n## Ključni izzivi avtonomnosti\n\n1. **Zaznavanje** -- robot mora razumeti okolje.\n2. **Načrtovanje** -- robot mora imeti cilj in pot.\n3. **Izvedba** -- robot mora natančno izvesti načrt.\n4. **Prilagajanje** -- robot mora reagirati na nepričakovano.\n\n---\n\n## Razmisli\n\nNa kateri stopnji avtonomnosti je:\n\n- Roomba sesalnik?\n- Mars rover?\n- Industrijski robotski krak?',
    updated_at = NOW()
WHERE title = 'Kaj pomeni avtonomnost?'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 4, Lesson 1: Samovozeči avtomobili
UPDATE course_lessons
SET content = E'# Samovozeči avtomobili\n\nSamovozeči avtomobili so eden najvidnejših primerov avtonomnih robotov.\n\n---\n\n## Kako delujejo?\n\n### Senzorji\n\n- **8+ kamer** -- 360-stopinjski pogled.\n- **LIDAR** -- 3D-zemljevid okolice.\n- **Radar** -- zaznava objektov v slabem vremenu.\n- **Ultrazvok** -- bližnji objekti pri parkiranju.\n\n### AI možgani\n\n1. Senzorji zajamejo podatke.\n2. AI prepozna: cesto, avtomobile, pešce, znake.\n3. AI načrtuje pot in hitrost.\n4. Izvede vožnjo skozi aktuatorje (volan, plin, zavore).\n\nVse to se zgodi **30-krat na sekundo**!\n\n---\n\n## Ključni igralci\n\n| Podjetje | Pristop | Status |\n|----------|---------|--------|\n| Waymo (Google) | LIDAR + kamere | Taxi v Phoenixu, SF |\n| Tesla | Samo kamere | Autopilot, FSD beta |\n| Cruise (GM) | LIDAR + kamere | Začasno ustavljeno |\n| Baidu Apollo | LIDAR + kamere | Taxi na Kitajskem |\n\n---\n\n## Etične dileme\n\nSamovozeči avto mora sprejemati težke odločitve:\n\n- Zavij levo (udari steno) ali desno (udari drevo)?\n- Zaustavi se nenadoma (potnike trese) ali nadaljuje?\n\nTo so vprašanja, ki jih morajo rešiti inženirji IN etiki skupaj.\n\n---\n\n## Aktivnost\n\nOblikuj mesto s petimi ulicami na papirju. Nariši pot samovozečega avtomobila in označi vse, kar mora zaznati (znake, pešce, luči, ovire).',
    updated_at = NOW()
WHERE title = 'Samovozeči avtomobili'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 4, Lesson 2: Roboti v vesolju
UPDATE course_lessons
SET content = E'# Roboti v vesolju\n\nVesolje je nevarno za ljudi, toda odlično za robote!\n\n---\n\n## Mars roverji\n\n### Curiosity (2012--danes)\n\n- Velikost avtomobila.\n- Jedrski vir energije.\n- Raziskuje površje Marsa, analizira kamenje.\n- Komunikacija z Zemljo traja 4--24 minut!\n\n### Perseverance (2021--danes)\n\n- Išče znake preteklega življenja.\n- S seboj je pripeljal **Ingenuity** -- prvi helikopter na drugem planetu!\n- Zbira vzorce za kasnejši transport na Zemljo.\n\n---\n\n## Zakaj roboti in ne ljudje?\n\n1. **Sevanje** -- vesolje je polno smrtonosnega sevanja.\n2. **Zrak** -- ni kisika za dihanje.\n3. **Čas** -- potovanje do Marsa traja 7 mesecev.\n4. **Stroški** -- robot je 100-krat cenejši od človeške misije.\n\n---\n\n## Izziv: Zakasnitev komunikacije\n\nSignal od Zemlje do Marsa potuje 4--24 minut.\n\n- Ne moreš "voziti" roverja v realnem času.\n- Rover mora biti delno **avtonomen** -- sam se izogiba nevarnostim.\n- Ukaze pošljemo enkrat na dan, rover jih izvede sam.\n\n---\n\n## Prihodnost\n\n- **Robotski gradbeniki** -- bodo gradili baze na Luni in Marsu pred prihodom ljudi.\n- **Robotski rudarji** -- bodo kopali minerale na asteroidih.\n- **Vesoljski teleskopi** -- robotski sistemi, ki sami popravljajo napake.\n\n---\n\n## Naloga\n\nNačrtuj robota za raziskovanje Jupitrovega meseca Evrope (pokrit z ledom, pod njim ocean). Kakšne senzorje in sposobnosti bi potreboval?',
    updated_at = NOW()
WHERE title = 'Roboti v vesolju'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 4, Lesson 3: Roji robotov (Swarm Robotics)
UPDATE course_lessons
SET content = E'# Roji robotov (Swarm Robotics)\n\nNamesto enega velikega robota -- tisoč majhnih, ki delajo skupaj!\n\n---\n\n## Navdih iz narave\n\n### Mravlje\n\n- Posamezna mravljica je preprosta.\n- Skupaj gradijo kompleksne kolonije.\n- Komunicirajo s feromoni (kemičnimi sledmi).\n\n### Čebele\n\n- Izvidnice najdejo cvetlice.\n- S plesom povedo drugim, kje je hrana.\n- Skupaj se odločijo za najboljši vir.\n\n### Ribe\n\n- Plavanje v jati za zaščito pred plenilci.\n- Nobena riba ni "vodja" -- vse sledijo enostavnim pravilom.\n\n---\n\n## Pravila za roj robotov\n\nVsak robot sledi trem enostavnim pravilom:\n\n1. **Separacija** -- ne pridi preblizu drugim.\n2. **Poravnava** -- premikaj se v isti smeri kot sosedje.\n3. **Kohezija** -- ostani blizu skupine.\n\nIz teh treh pravil nastane kompleksno skupinsko vedenje!\n\n---\n\n## Uporabe\n\n### Iskanje in reševanje\n\n- 100 majhnih dronov preišče ruševine po potresu.\n- Vsak pregleda majhno območje.\n- Ko eden najde osebo, pokliče ostale.\n\n### Kmetijstvo\n\n- Roji majhnih robotov sadijo, škropijo, žanjejo.\n- Vsak robot skrbi za svoj del polja.\n\n### Gradbeništvo\n\n- Majhni roboti skupaj gradijo strukture.\n- Kot termiti, ki gradijo termitnjake.\n\n---\n\n## Aktivnost\n\nZ razredom simulirajte roj: vsak učenec je "robot" in sledi trem pravilom. Opazujte, kaj se zgodi po 5 minutah premikanja po dvorani!',
    updated_at = NOW()
WHERE title = 'Roji robotov (Swarm Robotics)'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 4, Lesson 4: Projekt: Načrtuj avtonomno misijo
UPDATE course_lessons
SET content = E'# Projekt: Načrtuj avtonomno misijo\n\nČas je za velik projekt! Načrtuj celotno avtonomno robotsko misijo.\n\n---\n\n## Izberi scenarij\n\nIzberi ENEGA:\n\n### A) Podvodna raziskava\n\nRobot raziskuje morsko dno pri Piranu.\n\n- Kartira morsko dno.\n- Fotografira morsko življenje.\n- Zbira vzorce vode.\n\n### B) Mestna dostava\n\nRobot dostavlja pakete po Ljubljani.\n\n- Navigira po pločnikih.\n- Se izogiba pešcem.\n- Najde pravi naslov.\n\n### C) Gozdni nadzor\n\nRobot patruljira po slovenskem gozdu.\n\n- Zaznava gozdne požare.\n- Spremlja divje živali.\n- Poroča o stanju dreves.\n\n---\n\n## Za vsak scenarij opiši:\n\n### 1. Senzorji (2--3 strani)\n\n- Katere senzorje bo imel robot?\n- Zakaj prav te?\n\n### 2. AI sistemi (2--3 strani)\n\n- Kako bo robot sprejemal odločitve?\n- Katero vrsto strojnega učenja bo uporabil?\n\n### 3. Navigacija (1--2 strani)\n\n- Kako bo robot vedel, kje je?\n- Kako bo načrtoval pot?\n\n### 4. Komunikacija (1 stran)\n\n- Kako bo robot poročal človeku?\n- Kaj, če izgubi signal?\n\n### 5. Varnost (1 stran)\n\n- Kaj, če se robot pokvari?\n- Kako zaščitimo okolje pred robotom?\n\n---\n\n## Oddaj\n\nNapiši poročilo (5--10 strani) z risbami in diagrami. Bonus: naredi predstavitev za razred!',
    updated_at = NOW()
WHERE title = 'Projekt: Načrtuj avtonomno misijo'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 5, Lesson 0: Inženirski proces
UPDATE course_lessons
SET content = E'# Inženirski proces\n\nPravi inženirji sledijo strukturiranemu procesu pri razvoju robotov.\n\n---\n\n## 5 korakov inženirskega procesa\n\n### 1. Definiraj problem\n\n- Kakšno nalogo mora robot opravljati?\n- Kdo bo robota uporabljal?\n- Kakšne so omejitve (velikost, cena, energija)?\n\n### 2. Raziskuj\n\n- Ali že obstajajo podobni roboti?\n- Kakšne tehnologije so na voljo?\n- Kaj pravi znanost o problemu?\n\n### 3. Načrtuj\n\n- Nariši načrte robota.\n- Izberi komponente (senzorje, motorje, procesor).\n- Načrtuj programsko opremo.\n- Izračunaj stroške.\n\n### 4. Zgradi in testiraj\n\n- Sestavi prototip.\n- Testiraj v nadzorovanem okolju.\n- Zapiši rezultate.\n- Popravi napake.\n\n### 5. Izboljšaj\n\n- Analiziraj testne rezultate.\n- Kaj deluje dobro? Kaj ne?\n- Naredi spremembe.\n- Testiraj znova!\n\n---\n\n## Iteracija\n\nInženirski proces ni linearen -- je **krožen**. Vedno se vračamo na prejšnje korake in izboljšujemo.\n\n```\nDefiniraj → Raziskuj → Načrtuj → Zgradi → Testiraj\n    ↑                                         ↓\n    ←←←←←←←← Izboljšaj ←←←←←←←←←←←\n```\n\n---\n\n## Naloga\n\nZa svoj končni projekt zapiši:\n\n1. Problem, ki ga rešuješ.\n2. 3 obstoječe rešitve (raziskava).\n3. Prednosti tvojega pristopa.',
    updated_at = NOW()
WHERE title = 'Inženirski proces'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 5, Lesson 1: Načrtovanje mojega robota
UPDATE course_lessons
SET content = E'# Načrtovanje mojega robota\n\nČas je za načrtovanje tvojega lastnega robota!\n\n---\n\n## Korak 1: Izberi nalogo\n\nTvoj robot mora rešiti **resnični problem**. Nekaj idej:\n\n- Robot, ki pomaga starim staršem prinesti stvari.\n- Robot, ki čisti smetnjak.\n- Robot, ki pomaga pri učenju matematike.\n- Robot, ki skrbi za vrt, ko si na počitnicah.\n\n---\n\n## Korak 2: Zahteve\n\nZa vsako nalogo zapiši zahteve:\n\n| Zahteva | Opis | Prioriteta |\n|---------|------|------------|\n| Velikost | Največ 50 cm x 50 cm | Visoka |\n| Teža | Največ 5 kg | Srednja |\n| Energija | Baterija za 2 uri | Visoka |\n| Hitrost | 0,5 m/s | Nizka |\n\n---\n\n## Korak 3: Skica\n\nNariši robota iz treh pogledov:\n\n- Spredaj.\n- S strani.\n- Od zgoraj.\n\nOznači vse dele:\n\n- Kje so senzorji?\n- Kje je procesor?\n- Kje so motorji/kolesa?\n- Kje je baterija?\n\n---\n\n## Korak 4: Seznam komponent\n\n```\n1x Arduino Mega (procesor)       -- 25 EUR\n2x DC motor z gumijastimi kolesi -- 8 EUR\n1x Ultrazvočni senzor HC-SR04    -- 3 EUR\n1x Modul kamere                  -- 15 EUR\n1x Li-Po baterija 7,4 V          -- 12 EUR\n1x Robotsko šasijo (3D-tisk)     -- 10 EUR\n─────────────────────────────────\nSKUPAJ:                            73 EUR\n```\n\n---\n\n## Naloga\n\nIzpolni vse 4 korake za TVOJEGA robota. Oddaj načrt z risbami in seznamom komponent.',
    updated_at = NOW()
WHERE title = 'Načrtovanje mojega robota'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 5, Lesson 2: Programiranje robota
UPDATE course_lessons
SET content = E'# Programiranje robota\n\nSedaj, ko imamo načrt, napišimo program za robota!\n\n---\n\n## Psevdokoda\n\nPreden pišemo pravi program, napišemo **psevdokodo** -- program v navadnem jeziku.\n\n### Primer: Robot čistilec\n\n```\nPROGRAM robot_čistilec:\n\n  PONAVLJAJ:\n    slika = zajemi_sliko()\n    smeti = najdi_smeti(slika)\n\n    ČE smeti.najdene:\n      pot = izračunaj_pot(moja_lokacija, smeti.lokacija)\n      premikaj_se(pot)\n      poberi(smeti)\n      pot_do_koša = izračunaj_pot(moja_lokacija, koš)\n      premikaj_se(pot_do_koša)\n      odloži(smeti)\n    SICER:\n      premikaj_se_naključno()\n\n    ČE baterija < 20 %:\n      pot_domov = izračunaj_pot(moja_lokacija, polnilnica)\n      premikaj_se(pot_domov)\n      polni_se()\n  KONEC_PONAVLJAJ\n```\n\n---\n\n## Moduli programa\n\nRazdeli program na module:\n\n### Modul zaznave\n\n- Bere podatke iz senzorjev.\n- Procesira slike.\n- Vrne informacije o okolju.\n\n### Modul načrtovanja\n\n- Sprejema odločitve.\n- Računa pot.\n- Upravlja z nalogami.\n\n### Modul gibanja\n\n- Nadzoruje motorje.\n- Upravlja s hitrostjo.\n- Izvaja zavoje.\n\n### Modul varnosti\n\n- Preverja baterijo.\n- Zaznava trke.\n- Zasilna ustavitev.\n\n---\n\n## Naloga\n\nNapiši psevdokodo za TVOJEGA robota. Razdeli jo na vsaj 3 module.',
    updated_at = NOW()
WHERE title = 'Programiranje robota'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 5, Lesson 3: Testiranje in odpravljanje napak
UPDATE course_lessons
SET content = E'# Testiranje in odpravljanje napak\n\nNoben robot ne deluje popolno od začetka. Testiranje je ključno!\n\n---\n\n## Vrste testov\n\n### Enotski testi\n\nTestiramo posamezne dele:\n\n- Ali motor pravilno zavrti kolesa?\n- Ali senzor pravilno meri razdaljo?\n- Ali kamera zajame sliko?\n\n### Integracijski testi\n\nTestiramo, kako deli delujejo skupaj:\n\n- Ali robot zavije, ko senzor zazna oviro?\n- Ali pobere predmet, ko ga kamera prepozna?\n\n### Sistemski testi\n\nTestiramo celotnega robota v resničnem okolju:\n\n- Ali robot opravi nalogo od začetka do konca?\n- Koliko časa potrebuje?\n- Ali se pravilno obnaša v nepričakovanih situacijah?\n\n---\n\n## Pogosti problemi\n\n### Mehanski problemi\n\n- Kolesa drsijo → dodaj gumijaste obroče.\n- Robot se prevrne → znižaj težišče.\n- Prijemalnik ne prime → prilagodi pritisk.\n\n### Programski problemi (hrošči)\n\n- Robot se vrti v krogu → preveri smer motorjev.\n- Robot se zaleti v steno → senzor ne deluje pravilno.\n- Robot se ustavi brez razloga → preveri baterijo.\n\n### AI problemi\n\n- Robot ne prepozna predmetov → potrebuje več učnih podatkov.\n- Robot se odloča prepočasi → optimiziraj algoritem.\n\n---\n\n## Dnevnik testiranja\n\n| Test | Pričakovano | Dejansko | Status | Popravek |\n|------|-------------|----------|--------|-----------|\n| Vožnja 1 m naravnost | 1,00 m | 0,95 m | OK | / |\n| Obrat 90° | 90° | 105° | NAPAKA | Zmanjšaj čas motorja |\n\n---\n\n## Naloga\n\nSestavi načrt testiranja za svojega robota: 5 enotskih, 3 integracijske in 2 sistemska testa.',
    updated_at = NOW()
WHERE title = 'Testiranje in odpravljanje napak'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');

-- Module 5, Lesson 4: Končni projekt: Predstavitev
UPDATE course_lessons
SET content = E'# Končni projekt: Predstavitev\n\nČestitke! Prišel si do konca tečaja! Čas je za končno predstavitev.\n\n---\n\n## Kaj moraš oddati\n\n### 1. Pisno poročilo (8--12 strani)\n\n**Uvod** (1 stran)\n\n- Kakšen problem rešuješ?\n- Zakaj je ta problem pomemben?\n\n**Načrt robota** (3--4 strani)\n\n- Skica robota z oznakami.\n- Seznam komponent s cenami.\n- Razlaga izbire vsakega dela.\n\n**AI in programiranje** (2--3 strani)\n\n- Psevdokoda programa.\n- Razlaga AI algoritmov, ki jih uporabljaš.\n- Kako se robot uči/odloča?\n\n**Testni načrt** (1--2 strani)\n\n- Tabela testov.\n- Pričakovani rezultati.\n- Kako bi popravil napake?\n\n**Zaključek** (1 stran)\n\n- Kaj si se naučil?\n- Kaj bi izboljšal, če bi imel več časa?\n- Kako vidiš prihodnost tvojega robota?\n\n---\n\n### 2. Predstavitev (5--10 minut)\n\n- Pripravi diapozitive (8--12).\n- Predstavi problem, rešitev in rezultate.\n- Odgovori na vprašanja publike.\n\n---\n\n### 3. Demo (neobvezno)\n\n- Če si zgradil prototip ali simulacijo, jo pokaži!\n- Tudi papirni model ali risba je odlična.\n\n---\n\n## Ocenjevanje\n\n| Kriterij | Točke |\n|----------|-------|\n| Kreativnost problema | 20 |\n| Kakovost načrta | 25 |\n| Uporaba AI konceptov | 25 |\n| Predstavitev | 20 |\n| Testni načrt | 10 |\n| **SKUPAJ** | **100** |\n\n---\n\n## Nasveti\n\n- Bodi navdušen nad svojim projektom!\n- Razloži kompleksne koncepte enostavno.\n- Uporabi slike in diagrame.\n- Vadi predstavitev pred ogledalom.\n\n**Srečno in zabavaj se! Robotika je prihodnost!**',
    updated_at = NOW()
WHERE title = 'Končni projekt: Predstavitev'
  AND course_id = (SELECT id FROM courses WHERE slug = 'robotics-and-ai');
